"use client";
// Mirrors React-template Accordion.jsx — accordion-style-01 to 05

import { useState } from "react";

export interface AccordionItem {
  title: string;
  content: string;
  time?: string;
  author?: string;
}

interface Props {
  theme?: "accordion-style-01" | "accordion-style-02" | "accordion-style-03" | "accordion-style-04" | "accordion-style-05";
  data: AccordionItem[];
  defaultOpen?: number;
}

export default function Accordion({ theme = "accordion-style-01", data, defaultOpen = 0 }: Props) {
  const [open, setOpen] = useState(defaultOpen);
  const toggle = (i: number) => setOpen(open === i ? -1 : i);

  if (theme === "accordion-style-04") {
    return (
      <div className="accordion-style-04">
        {data.map((item, i) => (
          <div key={i} className={`acc-item ${open === i ? "open" : ""}`}>
            <div className="acc-header" onClick={() => toggle(i)}>
              {item.time && <span className="acc-time">{item.time}</span>}
              <span className="acc-title">{item.title}</span>
              {item.author && <span className="acc-author">{item.author}</span>}
              <span className="acc-toggle">{open === i ? "−" : "+"}</span>
            </div>
            <div className="acc-body">{item.content}</div>
          </div>
        ))}
      </div>
    );
  }

  if (theme === "accordion-style-05") {
    return (
      <div className="accordion-style-05">
        {data.map((item, i) => (
          <div key={i} className={`acc-item ${open === i ? "open" : ""}`}>
            <div className="acc-header" onClick={() => toggle(i)}>
              <span>{item.title}</span>
              <div className="acc-icon">{open === i ? "−" : "+"}</div>
            </div>
            <div className="acc-body">{item.content}</div>
          </div>
        ))}
      </div>
    );
  }

  return (
    <div className={theme}>
      {data.map((item, i) => (
        <div key={i} className={`acc-item ${open === i ? "open" : ""}`}>
          <button className="acc-trigger" onClick={() => toggle(i)}>
            <span>{item.title}</span>
            <svg
              className={`w-4 h-4 shrink-0 transition-transform ${open === i ? "rotate-180 text-[--primary]" : "text-gray-400"}`}
              viewBox="0 0 16 16" fill="currentColor"
            >
              <path d="M1.646 4.646a.5.5 0 0 1 .708 0L8 10.293l5.646-5.647a.5.5 0 0 1 .708.708l-6 6a.5.5 0 0 1-.708 0l-6-6a.5.5 0 0 1 0-.708" />
            </svg>
          </button>
          <div className="acc-body">
            <div className="acc-body-inner">{item.content}</div>
          </div>
        </div>
      ))}
    </div>
  );
}
